const data = $input.first().json;
const request = $('Prepare Input').item.json;

const safeNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  return Number.isFinite(num) ? num : null;
};

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const money = (value) => {
  const num = safeNumber(value);
  if (num === null) return 'N/A';
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(num);
};

const integer = (value) => {
  const num = safeNumber(value);
  if (num === null) return 'N/A';
  return new Intl.NumberFormat('en-US', { maximumFractionDigits: 0 }).format(num);
};

const percent = (value, digits = 1) => {
  const num = safeNumber(value);
  if (num === null) return 'N/A';
  return `${(num * 100).toFixed(digits)}%`;
};

const pts = (value, digits = 1) => {
  const num = safeNumber(value);
  if (num === null) return 'N/A';
  const scaled = num * 100;
  const sign = scaled > 0 ? '+' : '';
  return `${sign}${scaled.toFixed(digits)} pts`;
};

const pctDelta = (value) => {
  const num = safeNumber(value);
  if (num === null) return 'N/A';
  const scaled = num * 100;
  const sign = scaled > 0 ? '+' : '';
  return `${sign}${scaled.toFixed(1)}%`;
};

const metricRow = (label, current, priorMonth, priorYear, mom, yoy, formatter, deltaFormatter) => {
  const format = formatter || ((value) => value);
  const formatDelta = deltaFormatter || format;
  return `<tr><td>${escapeHtml(label)}</td><td>${format(current)}</td><td>${format(priorMonth)}</td><td>${format(priorYear)}</td><td>${formatDelta(mom)}</td><td>${formatDelta(yoy)}</td></tr>`;
};

const supplierId = data.supplier_id || request.supplierId;
const supplierName = data.supplier_name || `Supplier ${supplierId}`;
const currentMonth = data.current_month_label || 'Last closed month';
const priorMonth = data.prior_month_label || 'Previous month';
const priorYearMonth = data.prior_year_month_label || 'Prior year';
const portfolioOwner = data.portfolio_owner || request.portfolioOwner;
const contextNotes = request.contextNotes;
const subject = `Monthly Supplier Pre-Read | ${supplierName} (${supplierId}) | ${currentMonth}`;

let summaryItems = [];
let tableHtml = '';
let statusBanner = '';

if (!data.supplier_exists) {
  statusBanner = `<div class="banner warning">No supplier in the selected portfolio matched SuID <strong>${escapeHtml(supplierId)}</strong>.</div>`;
  summaryItems = [
    `Portfolio filter used: ${escapeHtml(portfolioOwner)}`,
    'Confirm the supplier ID is correct and that the supplier is assigned to this portfolio owner.',
    'No pre-read metrics were attached because the lookup returned no matching supplier.',
  ];
} else {
  if (safeNumber(data.current_grs) !== null) {
    summaryItems.push(`${escapeHtml(supplierName)} generated <strong>${money(data.current_grs)}</strong> in ${escapeHtml(currentMonth)} (${pctDelta(data.mom_grs_pct)} vs ${escapeHtml(priorMonth)}; ${pctDelta(data.yoy_grs_pct)} vs ${escapeHtml(priorYearMonth)}).`);
  }

  if (safeNumber(data.current_month_grs_rank) !== null || safeNumber(data.current_month_grs_share) !== null) {
    const rankText = safeNumber(data.current_month_grs_rank) === null ? 'N/A' : `#${integer(data.current_month_grs_rank)}`;
    summaryItems.push(`Current-month portfolio standing: <strong>${rankText}</strong> by GRS with <strong>${percent(data.current_month_grs_share)}</strong> of portfolio revenue.`);
  }

  if (safeNumber(data.current_visits) !== null || safeNumber(data.current_cvr) !== null) {
    summaryItems.push(`Traffic landed at <strong>${integer(data.current_visits)}</strong> visits with <strong>${percent(data.current_cvr)}</strong> CVR (${pts(data.mom_cvr_change)} vs ${escapeHtml(priorMonth)}).`);
  }

  if (safeNumber(data.current_availability) !== null || safeNumber(data.current_mrpi) !== null || safeNumber(data.current_wsi) !== null) {
    summaryItems.push(`Operational health snapshot: Availability <strong>${percent(data.current_availability)}</strong>, MRPI <strong>${percent(data.current_mrpi)}</strong>, WSI <strong>${percent(data.current_wsi)}</strong>.`);
  }

  tableHtml = `
    <table>
      <thead>
        <tr>
          <th>Metric</th>
          <th>${escapeHtml(currentMonth)}</th>
          <th>${escapeHtml(priorMonth)}</th>
          <th>${escapeHtml(priorYearMonth)}</th>
          <th>MoM</th>
          <th>YoY</th>
        </tr>
      </thead>
      <tbody>
        ${metricRow('GRS', data.current_grs, data.prior_month_grs, data.prior_year_grs, data.mom_grs_change, data.yoy_grs_change, money, money)}
        ${metricRow('Visits', data.current_visits, data.prior_month_visits, data.prior_year_visits, data.mom_visits_change, data.yoy_visits_change, integer, integer)}
        ${metricRow('CVR', data.current_cvr, data.prior_month_cvr, data.prior_year_cvr, data.mom_cvr_change, data.yoy_cvr_change, percent, pts)}
        ${metricRow('Availability', data.current_availability, data.prior_month_availability, data.prior_year_availability, data.mom_availability_change, data.yoy_availability_change, percent, pts)}
        ${metricRow('MRPI', data.current_mrpi, data.prior_month_mrpi, data.prior_year_mrpi, data.mom_mrpi_change, data.yoy_mrpi_change, percent, pts)}
        ${metricRow('WSI', data.current_wsi, data.prior_month_wsi, data.prior_year_wsi, data.mom_wsi_change, data.yoy_wsi_change, percent, pts)}
      </tbody>
    </table>
  `;
}

if (summaryItems.length === 0) {
  summaryItems.push('No comparable metrics were returned for this supplier in the selected reporting window.');
}

const contextBlock = contextNotes
  ? `<div class="callout"><h2>Meeting context</h2><p>${escapeHtml(contextNotes)}</p></div>`
  : '';

const htmlBody = `
<!DOCTYPE html>
<html>
  <head>
    <meta charset="UTF-8" />
    <style>
      body {
        font-family: Arial, sans-serif;
        color: #1f2933;
        line-height: 1.5;
        margin: 0;
        padding: 24px;
      }
      h1 {
        margin: 0 0 8px;
        background: #1f4e79;
        color: #fff;
        padding: 16px 18px;
        border-radius: 8px;
        font-size: 24px;
      }
      .subhead {
        margin: 12px 0 20px;
        color: #52606d;
      }
      h2 {
        color: #1f4e79;
        border-bottom: 2px solid #d9e2ec;
        padding-bottom: 4px;
        margin-top: 28px;
      }
      .banner {
        padding: 12px 14px;
        border-radius: 8px;
        margin: 16px 0;
      }
      .warning {
        background: #fff4db;
        color: #7c5a00;
        border: 1px solid #f0c36d;
      }
      .callout {
        background: #f7fafc;
        border: 1px solid #d9e2ec;
        border-radius: 8px;
        padding: 12px 14px;
        margin-top: 22px;
      }
      ul {
        padding-left: 22px;
      }
      table {
        width: 100%;
        border-collapse: collapse;
        margin-top: 14px;
        font-size: 13px;
      }
      th {
        background: #eaf2f8;
        text-align: left;
        padding: 8px;
        border: 1px solid #cbd2d9;
      }
      td {
        padding: 8px;
        border: 1px solid #d9e2ec;
      }
      tr:nth-child(even) {
        background: #f8fbfd;
      }
      .meta {
        color: #7b8794;
        font-size: 12px;
        margin-top: 20px;
      }
    </style>
  </head>
  <body>
    <h1>Monthly Supplier Pre-Read</h1>
    <div class="subhead"><strong>${escapeHtml(supplierName)}</strong> (SuID ${escapeHtml(supplierId)})<br/>Portfolio owner filter: ${escapeHtml(portfolioOwner)}<br/>Reporting month: ${escapeHtml(currentMonth)}</div>
    ${statusBanner}
    <h2>Executive summary</h2>
    <ul>${summaryItems.map((item) => `<li>${item}</li>`).join('')}</ul>
    <h2>Metric snapshot</h2>
    ${tableHtml || '<p><em>No metric table available for this supplier lookup.</em></p>'}
    ${contextBlock}
    <div class="meta">Generated automatically from n8n using the last fully closed month, the preceding month, and the same month last year.</div>
  </body>
</html>`;

return [{
  json: {
    sendTo: request.recipientEmail,
    subject,
    message: htmlBody,
    previewHtml: htmlBody,
  },
}];
